<template>
  <div class="section section-white">
    <div class="section-body">
      <el-form
        ref="form"
        :model="form"
        label-width="100px"
        label-position="right"
        class="demo-ruleForm"
      >
        <div v-if="!form.id" class="content-center content-bottom-padded">
          <el-radio-group v-model="form.tem_type" @change="handleTypeChange">
            <el-radio-button label="basic_entry"> 基礎錄入(統計報表) </el-radio-button>
            <el-radio-button label="ask_answer_paper"> 問卷調查 </el-radio-button>
          </el-radio-group>
        </div>
        <el-form-item
          label="標題"
          prop="tem_name"
          :rules="[{ required: true, message: '請輸入標題', trigger: 'blur' }]"
        >
          <el-col :span="20">
            <el-input v-model.trim="form.tem_name" :maxlength="30" placeholder="體測表單" />
          </el-col>
        </el-form-item>
        <el-form-item
          v-if="form.tem_type == 'ask_answer_paper'"
          label="表單風格"
          prop="form_style"
          :rules="[{ required: true, message: '請輸入標題', trigger: 'blur' }]"
        >
          <el-row :gutter="20">
            <el-col :span="5">
              <el-radio v-model="form.form_style" label="single"> 單頁問卷(多項集合) </el-radio>
              <!-- <el-radio v-model="form.form_style" label="multiple">多頁問卷(每頁一項)</el-radio> -->
            </el-col>
            <el-col :span="10">
              <el-alert
                v-if="form.form_style == 'single'"
                show-icon
                :closable="false"
                title="單頁問卷方式不支持圖片顯示"
                type="warning"
              />
              <el-alert
                v-if="form.form_style == 'multiple'"
                show-icon
                :closable="false"
                title="多頁問卷方式提供圖片顯示"
                type="warning"
              />
            </el-col>
          </el-row>
        </el-form-item>
        <el-form-item
          v-if="form.tem_type == 'ask_answer_paper' && form.form_style == 'single'"
          label="頭部文字"
        >
          <el-col :span="20">
            <el-input
              v-model.trim="form.header_link_title"
              type="textarea"
              :maxlength="500"
              placeholder="頭部文字超級連結"
            />
          </el-col>
        </el-form-item>
        <el-form-item
          v-if="form.tem_type == 'ask_answer_paper' && form.form_style == 'single'"
          label="頭部內容"
        >
          <el-col :span="20">
            <el-input
              v-model="form.header_title"
              type="textarea"
              :maxlength="500"
              placeholder="體測表單"
            />
          </el-col>
        </el-form-item>
        <el-form-item
          v-if="form.tem_type == 'ask_answer_paper' && form.form_style == 'single'"
          label="底部文字"
        >
          <el-col :span="20">
            <el-input
              v-model="form.bottom_title"
              type="textarea"
              :maxlength="500"
              placeholder="體測表單"
            />
          </el-col>
        </el-form-item>
        <el-form-item
          label="表單內容"
          prop="content"
          :rules="[{ required: true, message: '請選擇表單內容', trigger: 'change' }]"
        >
          <el-row v-for="(item, index) in form.content" :key="index" :gutter="2">
            <el-col :span="18">
              <el-card class="box-card">
                <div slot="header" class="clearfix">
                  <template v-if="form.tem_type == 'ask_answer_paper'">
                    <span>區塊一標題:</span
                    ><el-input
                      v-model="item.title"
                      placeholder="區塊標題"
                      size="mini"
                      style="width: 200px"
                    />
                    <span>排序:</span
                    ><el-input v-model="item.sort" size="mini" style="width: 50px" />
                  </template>
                  <el-button
                    style="float: right; padding: 3px 0"
                    type="text"
                    @click="checkContent(index)"
                  >
                    選擇表單內容
                  </el-button>
                </div>
                <el-col v-if="item.formdata.length > 0">
                  <el-table :data="item.formdata" style="width: 100%">
                    <el-table-column prop="id" label="ID" width="40" />
                    <el-table-column prop="field_title" label="標題" width="100" />
                    <el-table-column prop="sort" label="排序" width="100">
                      <template slot-scope="scope">
                        <el-input v-model="scope.row.sort" width="80" size="small" />
                      </template>
                    </el-table-column>
                    <el-table-column prop="sort" label="是否必填" width="100">
                      <template slot-scope="scope">
                        <el-checkbox
                          v-model="scope.row.is_required"
                          :checked="scope.row.is_required"
                        />
                      </template>
                    </el-table-column>
                    <el-table-column v-if="keyIndexIsShow" label="設置關鍵指數(最多設置5個)">
                      <template slot-scope="scope">
                        <el-checkbox
                          v-model="scope.row.key_index"
                          @change="checkKeyIndex(scope.$index, scope.row)"
                        />
                      </template>
                    </el-table-column>
                  </el-table>
                </el-col>
              </el-card>
            </el-col>
            <el-col v-if="form.tem_type == 'ask_answer_paper'" :span="2">
              <el-button v-if="index == 0" circle type="primary" @click="addCard"> 增 </el-button>
              <el-button v-if="index != 0" circle type="primary" @click="delCard(index)">
                刪
              </el-button>
            </el-col>
          </el-row>
        </el-form-item>
        <el-form-item
          v-if="keyIndexIsShow && form.key_index.length > 0"
          label="關鍵指數"
          prop="tem_name"
        >
          <el-row>
            <el-col v-for="(item, index) in form.key_index" :key="index" :span="4">
              <div>{{ item.field_title }}</div>
            </el-col>
          </el-row>
        </el-form-item>
        <el-form-item>
          <el-button @click.native="handleCancel"> 取消 </el-button>
          <el-button type="primary" @click="submitAction"> 儲存 </el-button>
        </el-form-item>
      </el-form>
    </div>
    <SideBar :visible.sync="showElementList" title="選擇表單元素" width="40">
      <slot>
        <el-row class="content-bottom-padded" :gutter="20">
          <el-col :span="6">
            <el-select
              v-model="params.form_element"
              placeholder="請選擇表單元素"
              style="width: 100%"
              clearable
              @change="searchData"
            >
              <el-option
                v-for="(item, key) in formElement"
                :key="item.value"
                :label="item.name"
                :value="item.value"
              />
            </el-select>
          </el-col>
          <el-col :span="6">
            <el-input v-model="params.field_title" placeholder="標題" style="width: 100%">
              <el-button slot="append" icon="el-icon-search" @click="searchData" />
            </el-input>
          </el-col>
        </el-row>
        <el-table
          ref="multipleTable"
          v-loading="loading"
          :data="ItemsList"
          tooltip-effect="dark"
          style="width: 100%"
          :row-key="getRowKeys"
          :select-on-indeterminate="false"
          @select="handleSelectChange"
          @select-all="handleSelectAll"
        >
          <el-table-column type="selection" :reserve-selection="true" width="50" />
          <el-table-column prop="id" label="ID" width="40" />
          <el-table-column prop="field_title" label="標題" width="150" />
          <el-table-column prop="form_element" label="元素" width="80" />
          <el-table-column label="選擇項">
            <template slot-scope="scope">
              <span v-for="(item, index) in scope.row.options" :key="index"> {{ item.value }}</span>
            </template>
          </el-table-column>
        </el-table>
        <div v-if="total_count > params.pageSize" class="tr">
          <el-pagination
            layout="prev, pager, next"
            :total="total_count"
            :page-size="params.pageSize"
            @current-change="handleCurrentChange"
          />
        </div>
        <span slot="footer" class="dialog-footer">
          <el-button type="primary" @click="saveStoreAction">確 定</el-button>
        </span>
      </slot>
    </SideBar>
  </div>
</template>

<script>
import { Message } from 'element-ui'
import {
  saveTemplate,
  getTemplateInfo,
  updateTemplate,
  getSettingList
} from '../../../api/selfhelpform'
import SideBar from '@/components/element/sideBar'

export default {
  inject: ['refresh'],
  components: {
    SideBar
  },
  data() {
    return {
      form: {
        id: '',
        tem_name: '',
        form_style: 'single',
        header_link_title: '',
        header_title: '',
        bottom_title: '',
        content: [{ title: '', sort: 1, formdata: [] }],
        tem_type: 'basic_entry',
        status: 1,
        key_index: []
      },
      params: {
        page: 1,
        pageSize: 10
      },
      settingList: [],
      total_count: 0,
      keyIndexIsShow: true,
      showElementList: false,
      ItemsList: [],
      loading: false,
      selectRows: [],
      formElement: [
        { name: '文本框', value: 'text' },
        { name: '文本域', value: 'textarea' },
        { name: '單選按鈕', value: 'radio' },
        { name: '複選框', value: 'checkbox' },
        { name: '下拉選擇框', value: 'select' },
        { name: '日期選擇', value: 'date' },
        { name: '地區地址選擇', value: 'area' },
        { name: '數字', value: 'number' }
      ],
      templateRadio: '',
      formcontentindex: 0,
      selectdata: []
    }
  },
  mounted() {
    if (this.$route.query.id) {
      getTemplateInfo(this.$route.query.id).then((res) => {
        this.form = res.data.data
        if (this.form.tem_type === 'basic_entry') {
          this.keyIndexIsShow = true
        } else {
          this.keyIndexIsShow = false
        }
      })
    }
  },
  methods: {
    getDataList() {
      this.loading = true
      getSettingList(this.params).then((response) => {
        this.ItemsList = response.data.data.list
        this.$refs.multipleTable.clearSelection()
        this.selectdata.forEach((item) => {
          let checked = this.ItemsList.find((n) => n.id === item.id)
          if (checked) {
            this.$refs.multipleTable.toggleRowSelection(item)
          }
        })
        this.loading = false
        this.total_count = response.data.data.total_count
      })
    },
    submitAction() {
      const that = this
      this.$refs['form'].validate((valid) => {
        if (valid) {
          if (this.form.tem_type == 'basic_entry' && this.form.key_index.length <= 0) {
            this.$message({
              type: 'error',
              message: '請配置關鍵數值'
            })
            return false
          }
          const postparams = JSON.parse(JSON.stringify(this.form))

          postparams.key_index = JSON.stringify(postparams.key_index)
          postparams.content = JSON.stringify(postparams.content)
          if (this.form.id) {
            updateTemplate(postparams).then((res) => {
              if (res.data.data) {
                this.$message({
                  message: '更新成功',
                  type: 'success',
                  duration: 2 * 1000,
                  onClose() {
                    that.refresh()
                    that.$router.go(-1)
                  }
                })
              }
            })
          } else {
            saveTemplate(postparams)
              .then((res) => {
                if (res.data.data) {
                  this.$message({
                    message: '新增成功',
                    type: 'success',
                    duration: 2 * 1000,
                    onClose() {
                      that.refresh()
                      that.$router.go(-1)
                    }
                  })
                }
              })
              .catch((error) => {
                this.$message({
                  type: 'error',
                  message: '儲存出錯'
                })
              })
          }
        } else {
          this.$message({
            type: 'error',
            message: '請錄入正確的數據'
          })
          return false
        }
      })
    },
    handleCancel() {
      this.$router.go(-1)
    },
    handleTypeChange(val) {
      this.showElementList = false
      this.form.tem_type = val
      if (val === 'basic_entry') {
        this.keyIndexIsShow = true
      } else {
        this.keyIndexIsShow = false
      }
    },
    checkIsRequired(index, val) {
      // console.log(val)
    },
    checkKeyIndex(index, val) {
      if (val.key_index && this.form.key_index.length >= 5) {
        this.form.content[index].key_index = false
        this.$message({
          type: 'error',
          message: '關鍵指數最高隻能選5個'
        })
        return false
      }
      if (this.form.key_index.length > 0) {
        let inChecked = this.form.key_index.findIndex((n) => val.id === n.id)
        if (inChecked !== -1) {
          this.form.key_index.splice(inChecked, 1)
        } else if (val.key_index) {
          this.form.key_index.push(val)
        }
      } else {
        this.form.key_index.push(val)
      }
    },
    checkContent(index) {
      if (this.form.tem_type == 'basic_entry') {
        this.params.form_element = 'number'
        this.formElement = [{ name: '數字', value: 'number' }]
      } else {
        this.params.form_element = ''
        this.formElement = [
          { name: '文本框', value: 'text' },
          { name: '文本域', value: 'textarea' },
          { name: '單選按鈕', value: 'radio' },
          { name: '複選框', value: 'checkbox' },
          { name: '下拉選擇框', value: 'select' },
          { name: '日期選擇', value: 'date' },
          { name: '地區地址選擇', value: 'area' },
          { name: '數字', value: 'number' }
        ]
      }
      this.showElementList = true
      this.formcontentindex = index
      this.selectdata = this.form.content[index].formdata
      this.getDataList()
    },
    searchData() {
      this.params.page = 1
      this.getDataList()
    },
    handleCurrentChange(page_num) {
      this.params.page = page_num
      this.getDataList()
    },
    handleSizeChange(pageSize) {
      this.loading = false
      this.params.page = 1
      this.params.pageSize = pageSize
      this.getDataList()
    },
    getRowKeys(row) {
      return row.id
    },
    getTemplateRow(index, row) {
      this.selectRows = new Array(row)
    },
    saveStoreAction() {
      let index = this.formcontentindex
      this.showElementList = false
      let newselectrows = JSON.parse(JSON.stringify(this.form.content[index].formdata))
      newselectrows.forEach((item) => {
        item.is_required = false
      })
      this.form.content[index].formdata = newselectrows
    },
    handleSelectAll(val) {
      let index = this.formcontentindex
      if (val.length > 0) {
        this.form.content[index].formdata = []
        val.forEach((item) => {
          let inChecked = this.form.content[index].formdata.findIndex((n) => item.id === n.id)
          if (inChecked === -1) {
            this.form.content[index].formdata.push(item)
          }
        })
      } else {
        this.ItemsList.forEach((item, index) => {
          let inChecked = this.form.content[index].formdata.findIndex((n) => item.id === n.id)
          if (inChecked !== -1) {
            this.form.content[index].formdata.splice(inChecked, 1)
          }
        })
      }
    },
    handleSelectChange(val, row) {
      let index = this.formcontentindex
      let inChecked = this.form.content[index].formdata.findIndex((item) => row.id === item.id)
      if (inChecked !== -1) {
        this.form.content[index].formdata.splice(inChecked, 1)
      } else {
        this.form.content[index].formdata.push(row)
      }
    },
    addCard() {
      let carddata = {
        title: '',
        formdata: [],
        sort: 1
      }
      this.form.content.push(carddata)
    },
    delCard(index) {
      this.form.content.splice(index, 1)
    }
  }
}
</script>
<style scoped lang="scss">
.clearfix:before,
.clearfix:after {
  display: table;
  content: '';
}
.clearfix:after {
  clear: both;
}

.box-card {
  width: 650px;
}
</style>
